// 在拦截器中使用缓存
public class MyCacheInterceptor : ICacheResponseInterceptor
{
    public async Task InterceptResponseAsync(HttpResponseMessage response, CancellationToken ct)
    {
        if (TryGetCached(response.RequestMessage.RequestUri.ToString(), out string? cachedResponse))
        {
            // 使用缓存的响应
            response.Content = new StringContent(cachedResponse);
        }
        else
        {
            // 发送请求并缓存结果
            var content = await response.Content.ReadAsStringAsync(ct);
            Set(response.RequestMessage.RequestUri.ToString(), content, 300); // 缓存5分钟
        }
    }
}

// 通过依赖注入获取
public class OrderService
{
    private readonly IEnhancedHttpClient _httpClient;

    public OrderService(IEnhancedHttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    public async Task<Order?> GetOrderAsync(int id)
    {
        return await _httpClient.GetAsync<Order>($"/api/orders/{id}");
    }
}

// 实现一个简单的表单内容
public class SimpleFormContent : IFormContent
{
    private readonly Dictionary<string, string> _formData;

    public SimpleFormContent(Dictionary<string, string> formData)
    {
        _formData = formData;
    }

    public HttpContent ToHttpContent()
    {
        return new FormUrlEncodedContent(_formData);
    }

    public Task<HttpContent> ToHttpContentAsync(IProgress<long>? progress = null, CancellationToken cancellationToken = default)
    {
        // 对于简单表单，同步和异步实现相同
        return Task.FromResult(ToHttpContent());
    }
}

// 使用示例
var formData = new Dictionary<string, string>
{
    { "username", "john" },
    { "email", "john@example.com" }
};
var formContent = new SimpleFormContent(formData);
var httpContent = formContent.ToHttpContent();

// 带进度报告的异步转换
var progress = new Progress<long>(bytesProcessed =>
{
    Console.WriteLine($"已处理: {bytesProcessed} 字节");
});

var httpContent = await formContent.ToHttpContentAsync(progress, cancellationToken);

[AllowAnyStatusCode]
[Get("/api/users/{id}")]
Task<Response<User>> GetUserAsync(int id);

// 使用示例
var response = await api.GetUserAsync(1);
if (response.StatusCode == HttpStatusCode.OK)
{
    var user = response.Content; // 访问反序列化的内容
}
else
{
    var error = response.ErrorContent; // 访问原始错误响应内容
}

