// 实现一个简单的 API 密钥提供者
public class ConfigurationApiKeyProvider : IApiKeyProvider
{
    private readonly IConfiguration _configuration;

    public ConfigurationApiKeyProvider(IConfiguration configuration)
    {
        _configuration = configuration;
    }

    public Task<string> GetApiKeyAsync(string? keyName = null, CancellationToken cancellationToken = default)
    {
        var key = _configuration.GetValue<string>($"ApiKeys:{keyName ?? "Default"}");
        return Task.FromResult(key ?? throw new InvalidOperationException("API Key not found"));
    }
}

// 使用示例
var provider = new ConfigurationApiKeyProvider(configuration);
var apiKey = await provider.GetApiKeyAsync("PaymentService");
httpClient.DefaultRequestHeaders.Add("X-API-Key", apiKey);

// 获取默认 API 密钥
var defaultKey = await apiKeyProvider.GetApiKeyAsync();

// 获取指定名称的 API 密钥
var paymentKey = await apiKeyProvider.GetApiKeyAsync("PaymentService");
var analyticsKey = await apiKeyProvider.GetApiKeyAsync("AnalyticsService");

// 在 HTTP 请求中使用
var request = new HttpRequestMessage(HttpMethod.Get, "https://api.example.com/data");
request.Headers.Add("X-API-Key", paymentKey);

// 实现 HMAC 签名提供者
public class HmacSha256SignatureProvider : IHmacSignatureProvider
{
    public async Task<string> GenerateSignatureAsync(HttpRequestMessage request, string secretKey, CancellationToken cancellationToken = default)
    {
        // 构建待签名字符串
        var stringToSign = $"{request.Method}\n{request.RequestUri}\n{await request.Content.ReadAsStringAsync(cancellationToken)}";

        // 使用 HMAC-SHA256 生成签名
        using var hmac = new HMACSHA256(Encoding.UTF8.GetBytes(secretKey));
        var hash = hmac.ComputeHash(Encoding.UTF8.GetBytes(stringToSign));
        return Convert.ToBase64String(hash);
    }

    public async Task<bool> VerifySignatureAsync(HttpRequestMessage request, string signature, string secretKey, CancellationToken cancellationToken = default)
    {
        var expectedSignature = await GenerateSignatureAsync(request, secretKey, cancellationToken);
        return expectedSignature == signature;
    }
}

// 使用示例
var provider = new HmacSha256SignatureProvider();
var signature = await provider.GenerateSignatureAsync(request, "my-secret-key");
request.Headers.Add("X-Signature", signature);

// 生成请求签名
var request = new HttpRequestMessage(HttpMethod.Post, "https://api.example.com/data");
request.Content = new StringContent("{\"key\":\"value\"}", Encoding.UTF8, "application/json");

var signature = await signatureProvider.GenerateSignatureAsync(request, "my-secret-key");
Console.WriteLine($"签名: {signature}");

// 验证请求签名
var signature = Request.Headers["X-Signature"];
var isValid = await signatureProvider.VerifySignatureAsync(request, signature, "my-secret-key");

if (isValid)
{
    Console.WriteLine("签名验证成功");
}
else
{
    Console.WriteLine("签名验证失败，请求可能被篡改");
}

// 创建令牌结果
var tokenResult = new TokenResult("access_token_123", DateTimeOffset.UtcNow.AddHours(1).ToUnixTimeMilliseconds(), "read write");

// 检查是否为空
if (!tokenResult.IsEmpty)
{
    Console.WriteLine($"令牌: {tokenResult.AccessToken}");
}

// 检查是否即将过期（默认5分钟内）
if (tokenResult.IsExpiringSoon())
{
    Console.WriteLine("令牌即将过期，需要刷新");
}

// 使用静态空值
var emptyResult = TokenResult.Empty;

// 检查是否在5分钟内过期
if (tokenResult.IsExpiringSoon(300))
{
    // 刷新令牌
}

// 检查是否在1分钟内过期
if (tokenResult.IsExpiringSoon(60))
{
    // 立即刷新令牌
}
